#include<bits/stdc++.h>
using namespace std;

struct node {
	long long data;
	long long la;
	int l, r;
};
node st[500005];
long long num[100005];
long long con(int l, int r, int id) {
	st[id].l = l;
	st[id].r = r;
	if (l == r) {
		st[id].data = num[l];
		return num[l];
	}
	int mid = (l + r) / 2;
	long long sum = 0;
	sum += con(l, mid, id * 2);
	sum += con(mid + 1, r, id * 2 + 1);
	st[id].data = sum;
	return sum;
}
void ladown(int id) {
	if (st[id].l == st[id].r) {
		st[id].la = 0;
		return;
	}
	long long temp = st[id].la;
	st[id].la = 0;
	int ml = id * 2;
	int mr = id * 2 + 1;
	st[ml].la += temp;
	st[ml].data += ((long long)(st[ml].r - st[ml].l + 1) * temp);
	st[mr].la += temp;
	st[mr].data += ((long long)(st[mr].r - st[mr].l + 1) * temp);
	return;
}
void op1(int l, int r, int id, long long k) {
	if (st[id]. l == l && st[id].r == r) {
		st[id].data += ((long long)(r - l + 1) * k);
		st[id].la += k;
		return;
	} else {
        ladown(id);
		int mid = (st[id].l + st[id].r) / 2;;
		if (r <= mid) {
			op1(l, r, id * 2, k);
		} else if (l > mid) {
			op1(l, r, id * 2 + 1, k);
		} else {
			op1(l, mid, id * 2, k);
			op1(mid + 1, r, id * 2 + 1, k);
		}
		st[id].data = (long long)(st[id * 2].data + st[id * 2 + 1].data);
		return;
	}
}
long long op2(int l, int r, int id) {
	if (st[id]. l == l && st[id].r == r) {
		return st[id].data;
	} else {
        ladown(id);
		int mid = (st[id].l + st[id].r) / 2;;

		if (r <= mid) {
			return op2(l, r, id * 2);
		} else if (l > mid) {
			return op2(l, r, id * 2 + 1);
		} else {
			long long sum = 0;
			sum += op2(l, mid, id * 2);
			sum += op2(mid + 1, r, id * 2 + 1);
			return sum;
		}
	}
}
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
	int n, m;
	cin >> n >> m;
	for (int i = 1; i <= n; i++) num[i]=i;
	con(1, n, 1);
	while (m--) {
		int opx;
		cin >> opx;
		if (opx == 1) {
			int x, y;
            long long k;
			cin >> x >> y >> k;
			op1(x, y, 1, k);
		} else {
			int x, y;
			cin >> x >> y;
            y=min(y,n);
			cout << op2(x, y, 1) << "\n";
		}
	}
	return 0;
}
